insert into recipes (
  code,
  name,
  category,
  status,
  prep_time_min,
  cook_time_min,
  cost_level,
  image_url,
  notes
) values
('RF001', 'Arroz de feijao com cenoura e couve', 'Vegetariana', 'por_testar', 10, 30, 'baixo', 'https://source.unsplash.com/1200x800/?rice,beans,stew', '1. Lavar o arroz e cortar a cenoura.\n2. Refogar os legumes em azeite.\n3. Juntar arroz, feijao cozido e agua suficiente para ficar malandrinho.\n4. Cozinhar ate o arroz abrir e o caldo ficar cremoso.\n5. Temperar com ervas e ajustar sal no fim.\n6. Servir quente.'),
('RF002', 'Massa com molho de abobora e lentilhas', 'Vegan', 'por_testar', 10, 25, 'baixo', 'https://source.unsplash.com/1200x800/?pumpkin,pasta,lentils', '1. Cozer a abobora com lentilhas vermelhas e tomate.\n2. Triturar parcialmente para obter um molho espesso.\n3. Cozer a massa ate ao ponto pretendido.\n4. Envolver a massa no molho e ajustar com agua da cozedura.\n5. Finalizar com azeite e pimenta.\n6. Servir com ervas frescas.'),
('RF003', 'Bacalhau espiritual adaptado sem leite', 'Peixe', 'por_testar', 20, 30, 'medio', 'https://source.unsplash.com/1200x800/?cod,potato,casserole', '1. Confirmar que o bacalhau esta bem demolhado e sem espinhas.\n2. Cozer batata e cenoura.\n3. Lascar o bacalhau e envolver com legumes e bebida vegetal.\n4. Cozinhar ate ficar cremoso.\n5. Levar ao forno para dourar.\n6. Servir com salada ou legumes verdes.'),
('RF004', 'Gratinado de batata, brocolos e grao', 'Vegan', 'por_testar', 15, 30, 'baixo', 'https://source.unsplash.com/1200x800/?potato,broccoli,chickpeas', '1. Cozer batata e brocolos.\n2. Envolver o grao com azeite e um pouco de agua quente.\n3. Montar uma travessa com batata, grao e brocolos.\n4. Temperar a gosto.\n5. Gratinar ate dourar.\n6. Servir como prato principal.'),
('RF005', 'Almondegas de lentilhas com arroz de tomate', 'Vegan', 'por_testar', 25, 30, 'baixo', 'https://source.unsplash.com/1200x800/?lentil,meatballs,tomato,rice', '1. Cozer lentilhas e escorrer.\n2. Misturar com aveia e cenoura ralada cozinhada ate formar uma massa moldavel.\n3. Formar almondegas e levar ao forno.\n4. Fazer arroz de tomate.\n5. Aquecer o molho e envolver as almondegas.\n6. Servir com o arroz.'),
('RF006', 'Sopa rica de grao, cenoura e batata-doce', 'Vegan', 'por_testar', 10, 30, 'baixo', 'https://source.unsplash.com/1200x800/?chickpea,soup,sweet,potato', '1. Cortar cenoura, batata-doce e tomate.\n2. Cozer com grao e couve.\n3. Triturar parcialmente.\n4. Ajustar a consistencia com agua se necessario.\n5. Temperar com azeite, sal e ervas.\n6. Servir quente.'),
('RF007', 'Massa espiral com ervilhas e molho de tomate', 'Vegan', 'por_testar', 10, 20, 'baixo', 'https://source.unsplash.com/1200x800/?pasta,peas,tomato', '1. Cozer a massa ate ao ponto pretendido.\n2. Cozinhar tomate triturado com cenoura ralada.\n3. Cozer ervilhas.\n4. Envolver massa, molho e ervilhas.\n5. Ajustar temperos com ervas, azeite e sal.\n6. Servir de imediato.'),
('RF008', 'Feijoada vegetariana com arroz', 'Vegan', 'por_testar', 15, 35, 'baixo', 'https://source.unsplash.com/1200x800/?white,beans,rice,stew', '1. Cozer cenoura e couve lombarda.\n2. Juntar feijao branco cozido e tomate.\n3. Cozinhar ate o caldo engrossar.\n4. Fazer arroz simples.\n5. Temperar a feijoada no fim.\n6. Servir com o arroz.'),
('RF009', 'Empadao de lentilhas e batata', 'Vegetariana', 'por_testar', 20, 35, 'baixo', 'https://source.unsplash.com/1200x800/?lentil,potato,pie', '1. Cozer batata e preparar o pure com azeite e agua da cozedura.\n2. Cozinhar lentilhas com cenoura e tomate.\n3. Deixar o recheio apurar.\n4. Montar o empadao com pure por cima.\n5. Gratinar no forno.\n6. Servir com salada.'),
('RF010', 'Arroz de pescada com cenoura e ervilhas', 'Peixe', 'por_testar', 10, 30, 'medio', 'https://source.unsplash.com/1200x800/?hake,rice,peas', '1. Cozer a pescada e retirar todas as espinhas.\n2. Fazer base com arroz, cenoura e agua.\n3. Juntar pescada lascada e ervilhas.\n4. Cozinhar ate o arroz ficar no ponto.\n5. Finalizar com azeite e ervas.\n6. Servir quente.'),
('RF011', 'Tortilha de batata, ervilhas e cenoura no forno', 'Vegetariana', 'por_testar', 15, 30, 'baixo', 'https://source.unsplash.com/1200x800/?potato,omelette,peas', '1. Cozer batata, cenoura e ervilhas.\n2. Bater ovos e temperar.\n3. Misturar legumes e ovos numa forma.\n4. Levar ao forno ate o centro ficar cozinhado.\n5. Cortar em fatias.\n6. Servir com salada.'),
('RF012', 'Estufado de grao com abobora e couscous', 'Vegan', 'por_testar', 10, 30, 'baixo', 'https://source.unsplash.com/1200x800/?chickpea,pumpkin,couscous', '1. Cozinhar abobora e brocolos com grao e tomate.\n2. Deixar a abobora integrar no molho.\n3. Hidratar couscous com agua quente e azeite.\n4. Temperar o estufado.\n5. Servir o estufado sobre o couscous.\n6. Finalizar com ervas ou especiarias.'),
('RF013', 'Massa de forno com lentilhas vermelhas e couve-flor', 'Vegan', 'por_testar', 15, 35, 'baixo', 'https://source.unsplash.com/1200x800/?baked,pasta,cauliflower,lentils', '1. Cozer massa e couve-flor.\n2. Cozinhar lentilhas vermelhas com tomate ate formar molho.\n3. Envolver tudo numa travessa.\n4. Temperar a gosto.\n5. Levar ao forno para gratinar.\n6. Servir quente.'),
('RF014', 'Hamburgueres de feijao preto e batata-doce', 'Vegan', 'por_testar', 20, 30, 'baixo', 'https://source.unsplash.com/1200x800/?black,bean,burger,sweet,potato', '1. Assar ou cozer batata-doce.\n2. Misturar feijao preto cozido com batata-doce e aveia.\n3. Moldar hamburgueres.\n4. Cozinhar no forno ate firmarem.\n5. Servir com arroz.\n6. Juntar molho ou salada a gosto.'),
('RF015', 'Acorda de grao e ovo com couve', 'Vegetariana', 'por_testar', 10, 25, 'baixo', 'https://source.unsplash.com/1200x800/?bread,egg,chickpeas,soup', '1. Demolhar pao em agua quente.\n2. Cozer couve.\n3. Juntar grao e ovo batido, mexendo ate cozinhar.\n4. Ajustar a consistencia com agua.\n5. Temperar no fim.\n6. Servir quente.'),
('RF016', 'Dahl de lentilhas vermelhas e espinafres', 'Vegan', 'por_testar', 10, 25, 'baixo', 'https://source.unsplash.com/1200x800/?red,lentil,dahl,spinach', '1. Cozer lentilhas vermelhas com cenoura e tomate.\n2. Juntar espinafres picados e cozinhar.\n3. Apurar o dahl.\n4. Servir com arroz.\n5. Temperar com especiarias.\n6. Finalizar com azeite ou ervas.'),
('RF017', 'Quinoa cremosa com grao, abobora e brocolos', 'Vegan', 'por_testar', 10, 25, 'medio', 'https://source.unsplash.com/1200x800/?quinoa,chickpeas,broccoli', '1. Lavar bem a quinoa.\n2. Cozer quinoa com abobora em cubos.\n3. Juntar grao cozido e brocolos no fim.\n4. Cozinhar ate a quinoa ficar no ponto.\n5. Finalizar com azeite e ervas.\n6. Servir quente.'),
('RF018', 'Croquetes de grao e cenoura com batata assada', 'Vegan', 'por_testar', 20, 30, 'baixo', 'https://source.unsplash.com/1200x800/?chickpea,fritters,carrot,potato', '1. Misturar grao cozido com cenoura ralada cozinhada e farinha de aveia.\n2. Moldar croquetes.\n3. Assar com pouco azeite.\n4. Assar batata em palitos.\n5. Preparar um molho a parte.\n6. Servir tudo junto.'),
('RF019', 'Risotto simples de cevadinha com ervilhas e cenoura', 'Vegetariana', 'por_testar', 10, 35, 'baixo', 'https://source.unsplash.com/1200x800/?barley,peas,carrot,risotto', '1. Cozer cevadinha lentamente.\n2. Juntar cenoura em cubos e ervilhas.\n3. Mexer ate ficar cremoso.\n4. Ajustar temperos.\n5. Finalizar com queijo ou azeite.\n6. Servir quente.'),
('RF020', 'Migas humidas de broa, feijao frade e grelos', 'Vegan', 'por_testar', 15, 25, 'baixo', 'https://source.unsplash.com/1200x800/?cornbread,beans,greens', '1. Cozer grelos e picar.\n2. Humedecer broa com agua quente.\n3. Juntar feijao frade cozido.\n4. Envolver tudo com azeite.\n5. Temperar com alho e sal.\n6. Servir como prato principal ou acompanhamento.'),
('RF021', 'Pataniscas de pescada no forno com arroz de legumes', 'Peixe', 'por_testar', 20, 25, 'medio', 'https://source.unsplash.com/1200x800/?fish,cakes,rice,vegetables', '1. Cozer pescada e retirar todas as espinhas.\n2. Misturar pescada lascada com ovo, farinha e cenoura ralada cozinhada.\n3. Formar discos e assar no forno.\n4. Fazer arroz de legumes.\n5. Temperar a gosto.\n6. Servir as pataniscas com o arroz.'),
('RF022', 'Jardineira vegetariana de feijao manteiga', 'Vegan', 'por_testar', 15, 35, 'baixo', 'https://source.unsplash.com/1200x800/?butter,beans,potatoes,stew', '1. Cozer batata e cenoura em cubos.\n2. Juntar feijao manteiga, ervilhas e tomate.\n3. Estufar ate o molho apurar.\n4. Ajustar temperos.\n5. Finalizar com azeite.\n6. Servir quente.'),
('RF023', 'Creme espesso de ervilhas, batata e ovo', 'Vegetariana', 'por_testar', 10, 25, 'baixo', 'https://source.unsplash.com/1200x800/?pea,soup,egg,potato', '1. Cozer batata, ervilhas e cenoura.\n2. Triturar ate ficar creme.\n3. Cozer ovos.\n4. Juntar ovo picado ao servir.\n5. Ajustar temperos.\n6. Finalizar com azeite.'),
('RF024', 'Salmao no forno com batata-doce e couve-flor', 'Peixe', 'por_testar', 10, 25, 'alto', 'https://source.unsplash.com/1200x800/?salmon,sweet,potato,cauliflower', '1. Assar batata-doce e couve-flor.\n2. Assar salmao ate ficar cozinhado.\n3. Verificar espinhas.\n4. Finalizar com limao, sal e ervas.\n5. Servir com os legumes assados.\n6. Regar com azeite se desejado.'),
('RF025', 'Arroz malandrinho de tomate, feijao branco e espinafres', 'Vegan', 'por_testar', 10, 30, 'baixo', 'https://source.unsplash.com/1200x800/?tomato,rice,white,beans,spinach', '1. Cozinhar tomate com arroz e agua.\n2. Juntar feijao branco cozido e espinafres picados.\n3. Deixar o arroz malandrinho.\n4. Ajustar temperos.\n5. Finalizar com azeite.\n6. Servir quente.')
on conflict (code) do update set
  name = excluded.name,
  category = excluded.category,
  prep_time_min = excluded.prep_time_min,
  cook_time_min = excluded.cook_time_min,
  cost_level = excluded.cost_level,
  image_url = excluded.image_url,
  notes = excluded.notes;

insert into family_rules (rule_key, rule_value) values
('family', '2 adultos'),
('no_meat', 'Nao usar carne'),
('fish_limit', 'Peixe no maximo 2 refeicoes por semana'),
('dairy', 'Evitar leite e derivados tradicionais; preferir alternativas vegetais adequadas'),
('preferences', 'Evitar cogumelos, cebola, curgete, beringela e tofu visiveis; usar triturado ou removivel')
on conflict (rule_key) do update set rule_value = excluded.rule_value;
